let selectedReminderDate = null;

Office.onReady((info) => {
  if (info.host === Office.HostType.Outlook) {
    document.getElementById("tomorrowMorning").onclick = () => setReminder("tomorrowMorning");
    document.getElementById("tomorrowEndDay").onclick = () => setReminder("tomorrowEndDay");
    document.getElementById("threeDays").onclick = () => setReminder("threeDays");
    document.getElementById("nextWeek").onclick = () => setReminder("nextWeek");

    document.getElementById("createCalendarItem").onclick = createCalendarReminder;
  }
});

function setReminder(option) {
  const status = document.getElementById("status");
  selectedReminderDate = getReminderDate(option);

  status.innerHTML = "Reminder will be set for:<br><strong>" + formatDate(selectedReminderDate) + "</strong>";
  status.style.display = "block";

  document.getElementById("createCalendarItem").style.display = "block";
}

function getReminderDate(option) {
  const date = new Date();

  if (option === "tomorrowMorning") {
    date.setDate(date.getDate() + 1);
    date.setHours(9, 0, 0, 0);
  }

  if (option === "tomorrowEndDay") {
    date.setDate(date.getDate() + 1);
    date.setHours(18, 0, 0, 0);
  }

  if (option === "threeDays") {
    date.setDate(date.getDate() + 3);
    date.setHours(9, 0, 0, 0);
  }

  if (option === "nextWeek") {
    date.setDate(date.getDate() + 7);
    date.setHours(9, 0, 0, 0);
  }

  return date;
}

function formatDate(date) {
  return date.toLocaleString("en-GB", {
    weekday: "short",
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit"
  });
}

function createCalendarReminder() {
  const status = document.getElementById("status");

  if (!selectedReminderDate) {
    status.innerHTML = "Please choose a reminder time first.";
    return;
  }

  const item = Office.context.mailbox.item;

  item.subject.getAsync((result) => {
    const emailSubject = result.value || "sent email";

    item.to.getAsync((toResult) => {
      let toRecipients = "";

      if (toResult.status === Office.AsyncResultStatus.Succeeded && toResult.value) {
        toRecipients = toResult.value
          .map((recipient) => recipient.emailAddress)
          .join(", ");
      }

      const start = selectedReminderDate;
      const end = new Date(selectedReminderDate.getTime() + 30 * 60000);

      const subject = encodeURIComponent("Follow up: " + emailSubject);

      const body = encodeURIComponent(
      "<strong>Email title:</strong> " +
      emailSubject +
      "<br><br><strong>Email address:</strong> " +
      toRecipients
);

      const url =
        "https://outlook.office.com/calendar/deeplink/compose" +
        "?subject=" + subject +
        "&startdt=" + encodeURIComponent(start.toISOString()) +
        "&enddt=" + encodeURIComponent(end.toISOString()) +
        "&body=" + body;

      Office.context.ui.openBrowserWindow(url);

      status.innerHTML = "Calendar reminder opened. Save it in Outlook Calendar.";
    });
  });
}